/**
 * MCP / A2A Authentication Generator (Node.js ESM build)
 *
 * Supports: none · bearer · basic · custom_headers
 * Usage:
 *   import { generateAuthConfig, authToHttpHeaders } from "./auth-generator.node.js";
 *   const auth = generateAuthConfig("bearer");
 *   const headers = authToHttpHeaders(auth);
 *
 * Generated by https://ruslanmv.com/assets/tools/auth-generator.html
 */

import crypto from "node:crypto";

const DEFAULT_TOKEN_BYTES = 32;

export function generateSecureToken(byteLength = DEFAULT_TOKEN_BYTES) {
  return crypto.randomBytes(byteLength).toString("base64url");
}

export function generateAuthConfig(authType, options = {}) {
  if (authType === "none") {
    return { type: "none" };
  }
  if (authType === "bearer") {
    return { type: "bearer", token: options.token || generateSecureToken(32) };
  }
  if (authType === "basic") {
    return {
      type: "basic",
      username: options.username || "demo-user",
      password: options.password || generateSecureToken(24),
    };
  }
  if (authType === "custom_headers") {
    return {
      type: "custom_headers",
      headers: {
        [options.headerName || "X-API-Key"]: options.headerValue || generateSecureToken(32),
      },
    };
  }
  throw new Error(`Unsupported authentication type: ${authType}`);
}

export function authToHttpHeaders(auth) {
  if (!auth || auth.type === "none") {
    return {};
  }
  if (auth.type === "bearer") {
    return { Authorization: `Bearer ${auth.token}` };
  }
  if (auth.type === "basic") {
    const encoded = Buffer.from(`${auth.username}:${auth.password}`, "utf8").toString("base64");
    return { Authorization: `Basic ${encoded}` };
  }
  if (auth.type === "custom_headers") {
    return { ...auth.headers };
  }
  throw new Error(`Unsupported authentication type: ${auth.type}`);
}
